class Solution {
    public int strangePrinter(String s) {
        int n = s.length();
        int[] dp = new int[n + 1];
        Arrays.fill(dp, n);
        dp[0] = 0;
        for (int i = 1; i <= n; i++) {
            char c = s.charAt(i - 1);
            for (int j = i - 1; j >= 1; j--) {
                if (s.charAt(j - 1) == c) {
                    dp[i] = Math.min(dp[i], dp[j] + 1);
                }
            }
        }
        return dp[n];
    }
}
